/**
 * inference.h  —  Zero-dependency neural network inference for SofconNet.
 *
 * Include this header + weights.h (generated by tools/export_weights.py)
 * in your submission file.  No external libraries required.
 *
 * Architecture mirrors model/network.py exactly:
 *   Stem Conv(c_in→64, 3x3) + BN + ReLU
 *   5x ResBlock(64)
 *   Policy head: Conv(64→2,1x1)+BN+ReLU → FC(2*H*W → H*W) → Softmax
 *   Value  head: Conv(64→1,1x1)+BN+ReLU → FC(H*W→256)+ReLU → FC(256→1)+Tanh
 */

