static inline float relu(float x) { return x > 0.f ? x : 0.f; }
static inline float fast_tanh(float x) {
    // accurate enough for inference
    if (x >  4.f) return  1.f;
    if (x < -4.f) return -1.f;
    float x2 = x * x;
    return x * (27.f + x2) / (27.f + 9.f * x2);
}

