static void conv2d(
    const float* in_data, int C_in,  int H,   int W,            //inputデータの情報     :  in_data  :  盤面15(H)×15(W)× 9のデータを表してます   tensor 1
    const float* w,       int C_out, int kH,  int kW,           //重みカーネルの情報    :   w       :   C_outは、16                            tensor 2
    const float* b,                                             //  バイアス    nullならばなし
    float* out,                                                 //  出力 tensor ( 15*15*16)
    int pad = 1, int stride = 1)                                //  padding を 1(in_dataの周りに0のパディングを付ける)  stride : カーネルのずらし量
{
    int H_out = (H + 2*pad - kH) / stride + 1;      //出力用テンソルの幅
    int W_out = (W + 2*pad - kW) / stride + 1;      //出力用テンソルの高

    for (int oc = 0; oc < C_out; ++oc) {                        //oc    出力テンソルの深さ
        for (int oh = 0; oh < H_out; ++oh) {                    //oh    出力テンソルの高さ
            for (int ow = 0; ow < W_out; ++ow) {                //ow    出力テンソルの幅
                float sum = b ? b[oc] : 0.f;                    //  b   バイアス

                for (int ic = 0; ic < C_in; ++ic) {                 //ic    入力テンソルの深さに対するループ
                    for (int kh = 0; kh < kH; ++kh) {                   //kh    0-カーネルの高さ
                        for (int kw = 0; kw < kW; ++kw) {               //kw    0-カーネルの幅
                            int ih = oh*stride - pad + kh;                  //  ih  :   出力カーネルの書き込み位置
                            int iw = ow*stride - pad + kw;                  //  iw  :   出力カーネルの書き込み位置
                            if (ih < 0 || ih >= H || iw < 0 || iw >= W) continue;       //ih,iw がカーネルの平面から、 外れている場合は、計算しない
                            int in_idx  = (ic*H + ih)*W + iw;                           //in_idx    :   入力データのidx
                            //
                            int w_idx   = ((oc*C_in + ic)*kH + kh)*kW + kw;             //w_idx     :   カーネルデータのidx
                            sum += in_data[in_idx] * w[w_idx];                              //sum : 
                        }
                    }
                }
                out[(oc*H_out + oh)*W_out + ow] = sum;
            }
        }
    }
}

// Batch-norm (inference mode, no running stats update)
// x, out: (C, H, W)  gamma/beta/mean/var: (C,)
static void batch_norm(
    const float* x, int C, int H, int W,
    const float* gamma, const float* beta,
    const float* running_mean, const float* running_var,
    float eps, float* out)
{
    int hw = H * W;
    for (int c = 0; c < C; ++c) {
        float scale = gamma[c] / std::sqrt(running_var[c] + eps);
        float shift = beta[c] - running_mean[c] * scale;
        const float* src = x   + c * hw;
        float*       dst = out + c * hw;
        for (int i = 0; i < hw; ++i)
            dst[i] = src[i] * scale + shift;
    }
}

// in-place relu on (C,H,W) tensor
static void relu_inplace(float* x, int n) {
    for (int i = 0; i < n; ++i) x[i] = relu(x[i]);
}

// residual add: out[i] += x[i], then relu
static void add_relu(float* out, const float* x, int n) {
    for (int i = 0; i < n; ++i) out[i] = relu(out[i] + x[i]);
}

// FC: out[j] = sum_i in_data[i]*w[j*in_features+i] + b[j]
static void linear(
    const float* in_data, int in_features,
    const float* w, const float* b,
    float* out, int out_features)
{
    for (int j = 0; j < out_features; ++j) {
        float s = b ? b[j] : 0.f;
        const float* row = w + j * in_features;
        for (int i = 0; i < in_features; ++i) s += in_data[i] * row[i];
        out[j] = s;
    }
}

static void softmax(float* x, int n) {
    float mx = *std::max_element(x, x+n);
    float sum = 0.f;
    for (int i = 0; i < n; ++i) { x[i] = std::exp(x[i] - mx); sum += x[i]; }
    for (int i = 0; i < n; ++i) x[i] /= sum;
}

